import json
import re
from dataclasses import dataclass
from pathlib import Path
from typing import List, Optional, Tuple

import torch
from peft import PeftModel
from transformers import AutoProcessor, Qwen2_5_VLForConditionalGeneration

MIN_PIXELS = 256 * 28 * 28
MAX_PIXELS = 512 * 28 * 28
GRID = 1000.0


@dataclass
class ParsedPrediction:
    kind: str
    values: List[float]
    raw_text: str = ""


def _read_json(path: Path):
    try:
        return json.loads(path.read_text())
    except Exception:
        return {}


def _has_model_files(path: Path) -> bool:
    if not path.exists() or not path.is_dir():
        return False
    names = [
        "config.json",
        "model.safetensors.index.json",
        "model-00001-of-00002.safetensors",
        "pytorch_model.bin",
    ]
    return any((path / n).exists() for n in names)


def resolve_base_model_dir(checkpoint: str) -> str:
    ckpt = Path(checkpoint).resolve()
    ckpt_dir = ckpt if ckpt.is_dir() else ckpt.parent
    meta = _read_json(ckpt_dir / "meta.json")
    cwd = Path.cwd().resolve()
    candidates = [
        ckpt_dir / "base_model",
        ckpt_dir.parent / "base_model",
        ckpt_dir.parent / "baseline" / "base_model",
        cwd / "checkpoints" / ckpt_dir.name / "base_model",
        cwd / "checkpoints" / "baseline" / "base_model",
        Path("/workspace/checkpoints") / ckpt_dir.name / "base_model",
        Path("/workspace/checkpoints/baseline/base_model"),
        Path("/data/base_model/Qwen2.5-VL-3B-Instruct"),
    ]
    for key in ["base_model_dir", "base_model", "base_dir"]:
        val = meta.get(key)
        if val:
            p = Path(val)
            candidates.append(p if p.is_absolute() else (ckpt_dir / p).resolve())
            candidates.append(p if p.is_absolute() else (cwd / p).resolve())
    seen = set()
    for c in candidates:
        s = str(c)
        if s in seen:
            continue
        seen.add(s)
        if _has_model_files(c):
            return s
    raise FileNotFoundError(f"base model not found for checkpoint {checkpoint}; checked: {candidates}")


def load_model_for_inference(checkpoint: str, min_pixels: int = MIN_PIXELS, max_pixels: int = MAX_PIXELS):
    ckpt = Path(checkpoint).resolve()
    base_dir = resolve_base_model_dir(checkpoint)

    processor = None
    last_err = None
    for cand in [ckpt / "processor", ckpt, Path(base_dir)]:
        if not Path(cand).exists():
            continue
        try:
            processor = AutoProcessor.from_pretrained(
                str(cand),
                local_files_only=True,
                trust_remote_code=False,
                min_pixels=min_pixels,
                max_pixels=max_pixels,
            )
            break
        except Exception as e:
            last_err = e
    if processor is None:
        raise last_err if last_err is not None else RuntimeError("processor load failed")

    model = Qwen2_5_VLForConditionalGeneration.from_pretrained(
        base_dir,
        torch_dtype=torch.bfloat16,
        local_files_only=True,
        trust_remote_code=False,
        device_map="auto",
    )
    if (ckpt / "adapter_config.json").exists():
        model = PeftModel.from_pretrained(model, str(ckpt), local_files_only=True)
    model.eval()
    return model, processor


def build_messages(instruction: str):
    text = (
        "Locate the UI element described by the instruction. "
        "Return only one point using image-grid coordinates from 0 to 1000 in the exact format <point>x y</point>.\n"
        f"Instruction: {instruction}"
    )
    return [{"role": "user", "content": [{"type": "image"}, {"type": "text", "text": text}]}]


def _extract_numbers(text: str) -> List[float]:
    return [float(x) for x in re.findall(r"-?\d+(?:\.\d+)?", text)]


def parse_prediction_text(raw_text: str) -> Optional[ParsedPrediction]:
    if raw_text is None:
        return None
    text = raw_text.strip()
    if not text:
        return None

    patterns = [
        ("point", r"<point>\s*([^<]+?)\s*</point>"),
        ("point", r"point\s*[:=]\s*\(?\s*([^)\n]+)\)?"),
        ("box", r"<box>\s*([^<]+?)\s*</box>"),
        ("box", r"<bbox>\s*([^<]+?)\s*</bbox>"),
    ]
    for kind, pat in patterns:
        m = re.search(pat, text, flags=re.I | re.S)
        if not m:
            continue
        nums = _extract_numbers(m.group(1))
        if kind == "point" and len(nums) >= 2:
            return ParsedPrediction("point", nums[:2], text)
        if kind == "box" and len(nums) >= 4:
            x1, y1, x2, y2 = nums[:4]
            return ParsedPrediction("point", [(x1 + x2) / 2.0, (y1 + y2) / 2.0], text)

    nums = _extract_numbers(text)
    if len(nums) >= 4:
        x1, y1, x2, y2 = nums[:4]
        return ParsedPrediction("point", [(x1 + x2) / 2.0, (y1 + y2) / 2.0], text)
    if len(nums) >= 2:
        return ParsedPrediction("point", nums[:2], text)
    return None


def _clip(v: float, lo: float, hi: float) -> float:
    return max(lo, min(hi, float(v)))


def scale_point_from_grid(x: float, y: float, image_width: float, image_height: float, grid: float = GRID) -> Tuple[float, float]:
    px = x / grid * float(image_width)
    py = y / grid * float(image_height)
    return _clip(px, 0.0, float(image_width)), _clip(py, 0.0, float(image_height))


def generate_raw(model, processor, image, instruction: str, max_new_tokens: int = 32) -> str:
    messages = build_messages(instruction)
    prompt = processor.apply_chat_template(messages, tokenize=False, add_generation_prompt=True)
    inputs = processor(text=[prompt], images=[image], padding=True, return_tensors="pt")
    inputs = {k: v.to(model.device) if hasattr(v, "to") else v for k, v in inputs.items()}
    with torch.inference_mode():
        out = model.generate(
            **inputs,
            max_new_tokens=max_new_tokens,
            do_sample=False,
            use_cache=True,
        )
    prompt_len = inputs["input_ids"].shape[1]
    gen_ids = out[:, prompt_len:]
    text = processor.batch_decode(gen_ids, skip_special_tokens=True, clean_up_tokenization_spaces=False)[0]
    return text.strip()


def generate_prediction(model, processor, image, instruction: str, image_width: float, image_height: float):
    raw = generate_raw(model, processor, image, instruction)
    parsed = parse_prediction_text(raw)
    if parsed is None or parsed.kind != "point" or len(parsed.values) < 2:
        return {"point": [float(image_width) / 2.0, float(image_height) / 2.0], "raw": raw}
    x, y = scale_point_from_grid(parsed.values[0], parsed.values[1], image_width, image_height)
    return {"point": [x, y], "raw": raw}
